var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0037: <color=#ffd34c>서윤</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0037：<color=#ffd34c>アオイ・シズカ</color>","ENG":"[[","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0037: <color=#ffd34c>徐芸</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เริ่มการทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข AS001L0037: <color=#ffd34c>ซอ ยุน</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số AS001L0037: <color=#ffd34c>Seo Yoon</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>      \\nCCN No. AS001L0037: <color=#ffd34c>徐芸</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. AS001L0037: <color=#ffd34c>Seo Yoon</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. AS001L0037\xA0: <color=#ffd34c>Seo Yoon</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"룰루~ 룰루루~","JPN":"ルル～ルルル～～。","ENG":"Lala, lalala!","TWN":"嚕嚕～嚕嚕嚕～"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"기분이 좋아 보이는군. 별일인데?","JPN":"珍しくご機嫌だな？","ENG":"You look happy. That's unusual.","TWN":"你心情看起來很好呢。發生什麼事了嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"무슨 뜻이죠, 그 말씀은?","JPN":"どういう意味ですか？","ENG":"What do you mean by that?","TWN":"你這話是什麼意思？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"마치 전 행복해하면 안 된다는 것처럼 들립니다만?","JPN":"私の幸せが気に入らないようですね？","ENG":"It sounds as if I'm never supposed to be happy.","TWN":"聽起來好像我不該這麼開心一樣？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 아니, 그럴 리가 있겠나?","JPN":"い、いや。そんなわけないだろう？","ENG":"W-what? Of course not.","TWN":"不、不是，我怎麼敢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"난 언제나 자네가 즐겁게 일할 수 있는 환경을 만들어 주려고 노력하고 있다네.","JPN":"私は常に君が楽しく働ける環境を整えるために、最善を尽くしてる。","ENG":"I'm always trying hard to provide the best work environment for you to enjoy.","TWN":"我一直在努力為你創造一個愉快的工作環境。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래서 말인데, 얼굴이 밝아 보이는군.","JPN":"それでだな、ずいぶんと表情が明るいが。","ENG":"Speaking of which, you look good.","TWN":"然後，就看到你氣色很好的樣子。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"뭐 좋은 일이라도 있나?","JPN":"何かいい事でもあったのか？","ENG":"Do you have some good news?","TWN":"是有什麼好事嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그야 좋다면 좋은 일이죠.","JPN":"そうとも言えますね。","ENG":"I suppose it can be considered good.","TWN":"說好的話應該可以算好事吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"항상 본사의 들쭉날쭉한 작전수행 능력 때문에 골머리를 앓아 왔었는데......","JPN":"我が社の不安定な作戦遂行能力のせいで、いつも頭を抱えていたのですが……","ENG":"I was having trouble with our company's unreliable mission capability...","TWN":"之前一直在為本公司亂七八糟的作戰達成能力感到頭痛……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"드디어 제 2소대를 편성할 수 있을 것 같습니다.","JPN":"やっと第2小隊を編成できそうです。","ENG":"But I believe we can finally form a 2nd squad.","TWN":"現在終於可以組建第二小隊了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이것도 모두 회사의 재정이 안정된 덕분이죠.","JPN":"これもすべて、会社の財政が安定したおかげです。","ENG":"And this is all thanks to our company's improved financial status.","TWN":"這全多虧公司的財政穩定了下來。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"제 2소대의 편성이 끝나면 당분간은 스승님의 변덕 때문에 회사가 휘둘리는 일도 없을 겁니다.","JPN":"第2小隊の編成を終えれば、当分の間は師匠の気まぐれに会社が振り回されることもないでしょう。","ENG":"Once the 2nd squad is formed, the company won't have to suffer from Master's unpredictable actions for a while.","TWN":"第二小隊的組建完成後，公司暫時就不用被師父的任性牽著走了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그러니까 쇼핑을 해서 기분이 좋았다는 거였군.","JPN":"……つまり、良い買い物をして機嫌がよかったということだな。","ENG":"So you're saying that you're happy because you went shopping.","TWN":"……所以就是買完東西後，心情變好的意思吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네? 방금 무슨 말씀을 하셨죠?","JPN":"はい？今、何ておっしゃいましたか？","ENG":"Huh? What do you mean by that?","TWN":"咦？您剛才說什麼？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 아무것도 아닐세. 그래서 적당한 후보는 찾았나?","JPN":"な、何でもない。それで、適切な候補は見つかったのか？","ENG":"I-it's nothing. So, did you find a reasonable candidate?","TWN":"沒，沒什麼。所以，你找到合適的候補了嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"내 기억엔 예전부터 자네 눈이 꽤 높았던 걸로 아는데 말이야.","JPN":"私の記憶では、君の基準はかなり厳しかったはずだが。","ENG":"From what I remember, you've always had high standards.","TWN":"在我的記憶中，你的眼光一直都很高。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 기준을 충족하는 인재라니 나도 기대되는군.","JPN":"それを満たす人材が現れたのなら、私も楽しみだ。","ENG":"I can't wait to meet the person who satisfied your standards.","TWN":"竟然能滿足你的標準，我也跟著期待了起來呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};